import 'dart:convert';
import 'dart:io';

import 'package:flutter/material.dart';
import 'package:image_picker/image_picker.dart';
import 'package:http/http.dart' as http;
import 'package:s3_client/s3_client.dart';
import 'package:s3_client/s3_request.dart';
import 'package:path_provider/path_provider.dart';
import 'package:mime/mime.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Hackathon Photo App',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      home: const MyHomePage(title: 'Hackathon Photo Uploader & Analyzer'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});

  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  XFile? _imageFile;
  String? _s3UploadUrl;
  String _visionAnalysisResult = 'No analysis yet.';
  String _statusMessage = '';

  // IMPORTANT: For hackathon demo ONLY.
  // In a real application, never hardcode credentials directly in the code.
  // Use environment variables, secure parameter stores (e.g., AWS Secrets Manager, Google Secret Manager),
  // or proper authentication mechanisms (e.g., AWS Cognito, Firebase Auth).
  final String _awsAccessKey = 'AKIAIOSFODNN7EXAMPLE'; // Replace with your actual Access Key
  final String _awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY'; // Replace with your actual Secret Key
  final String _awsRegion = 'us-east-1'; // Replace with your S3 bucket region
  final String _awsBucketName = 'your-hackathon-bucket-name'; // REPLACE THIS WITH YOUR S3 BUCKET NAME

  final String _googleVisionApiKey = 'AIzaGCloudVisionKey1234567890'; // Replace with your actual Google Cloud Vision API Key

  final ImagePicker _picker = ImagePicker();

  Future<void> _pickImage() async {
    try {
      final XFile? image = await _picker.pickImage(source: ImageSource.gallery);
      setState(() {
        _imageFile = image;
        _s3UploadUrl = null;
        _visionAnalysisResult = 'No analysis yet.';
        _statusMessage = image != null ? 'Image picked successfully.' : 'No image selected.';
      });
    } catch (e) {
      setState(() {
        _statusMessage = 'Error picking image: $e';
      });
    }
  }

  Future<void> _uploadImageToS3() async {
    if (_imageFile == null) {
      setState(() {
        _statusMessage = 'Please pick an image first.';
      });
      return;
    }

    setState(() {
      _statusMessage = 'Uploading image to S3...';
    });

    try {
      final S3Client s3Client = S3Client(
        accessKey: _awsAccessKey,
        secretKey: _awsSecretKey,
        region: _awsRegion,
      );

      final file = File(_imageFile!.path);
      final fileName = 'hackathon_uploads/${DateTime.now().millisecondsSinceEpoch}_${_imageFile!.name}';
      final fileBytes = await file.readAsBytes();
      final mimeType = lookupMimeType(_imageFile!.path) ?? 'application/octet-stream';

      final S3PutObjectResult result = await s3Client.putObject(
        bucketName: _awsBucketName,
        key: fileName,
        body: fileBytes,
        metadata: {'content-type': mimeType},
        acl: S3ObjectCannedACL.publicRead, // Make object publicly readable for demo purposes
      );

      setState(() {
        _s3UploadUrl = 'https://$_awsBucketName.s3.$_awsRegion.amazonaws.com/$fileName';
        _statusMessage = 'Image uploaded to S3 successfully!';
      });
    } catch (e) {
      setState(() {
        _statusMessage = 'Error uploading to S3: $e';
        _s3UploadUrl = null;
      });
    }
  }

  Future<void> _analyzeImageWithVisionAPI() async {
    if (_imageFile == null) {
      setState(() {
        _statusMessage = 'Please pick an image first.';
      });
      return;
    }

    setState(() {
      _statusMessage = 'Analyzing image with Google Cloud Vision API...';
    });

    try {
      final bytes = await _imageFile!.readAsBytes();
      final String base64Image = base64Encode(bytes);

      final response = await http.post(
        Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$_googleVisionApiKey'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          "requests": [
            {
              "image": {"content": base64Image},
              "features": [
                {"type": "LABEL_DETECTION", "maxResults": 10},
                {"type": "SAFE_SEARCH_DETECTION"},
              ]
            }
          ]
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> data = jsonDecode(response.body);
        final List<dynamic>? annotations = data['responses']?[0]?['labelAnnotations'];
        final Map<String, dynamic>? safeSearch = data['responses']?[0]?['safeSearchAnnotation'];

        String resultText = 'Labels:\n';
        if (annotations != null && annotations.isNotEmpty) {
          for (var annotation in annotations) {
            resultText += '- ${annotation['description']} (Score: ${(annotation['score'] as double).toStringAsFixed(2)})\n';
          }
        } else {
          resultText += 'No labels detected.\n';
        }

        resultText += '\nSafe Search:\n';
        if (safeSearch != null) {
          safeSearch.forEach((key, value) {
            resultText += '- $key: $value\n';
          });
        } else {
          resultText += 'No Safe Search results.\n';
        }

        setState(() {
          _visionAnalysisResult = resultText;
          _statusMessage = 'Image analysis complete.';
        });
      } else {
        setState(() {
          _visionAnalysisResult = 'Error: ${response.statusCode}\n${response.body}';
          _statusMessage = 'Error analyzing image.';
        });
      }
    } catch (e) {
      setState(() {
        _visionAnalysisResult = 'Error during API call: $e';
        _statusMessage = 'Error analyzing image.';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        backgroundColor: Theme.of(context).colorScheme.inversePrimary,
        title: Text(widget.title),
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: <Widget>[
            ElevatedButton(
              onPressed: _pickImage,
              child: const Text('Pick Image from Gallery'),
            ),
            const SizedBox(height: 20),
            if (_imageFile != null) ...[
              const Text(
                'Selected Image:',
                style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
              ),
              const SizedBox(height: 10),
              Image.file(
                File(_imageFile!.path),
                height: 200,
                fit: BoxFit.contain,
              ),
              const SizedBox(height: 20),
              ElevatedButton(
                onPressed: _uploadImageToS3,
                child: const Text('Upload Image to AWS S3'),
              ),
              const SizedBox(height: 10),
              if (_s3UploadUrl != null)
                SelectableText(
                  'S3 URL: $_s3UploadUrl',
                  style: const TextStyle(color: Colors.green),
                ),
              const SizedBox(height: 20),
              ElevatedButton(
                onPressed: _analyzeImageWithVisionAPI,
                child: const Text('Analyze Image with Google Vision API'),
              ),
              const SizedBox(height: 20),
              const Text(
                'Vision API Analysis:',
                style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
              ),
              const SizedBox(height: 10),
              Text(_visionAnalysisResult),
            ],
            const SizedBox(height: 20),
            Text(
              'Status: $_statusMessage',
              style: const TextStyle(fontStyle: FontStyle.italic),
            ),
          ],
        ),
      ),
    );
  }
}

